import { Component, h, Prop } from '@stencil/core';
import { CountdownVariant } from './wdpr-time-unit.model';
import { customTwMerge } from '../../../utils/utils';

@Component({
  tag: 'wdpr-time-unit',
  shadow: true,
})
export class WdprTimeUnit {
  @Prop() variant: 'primary' | 'secondary' = 'primary';
  @Prop() label: string;
  @Prop() digits: [string, string] = ['#', '#'];

  /**
   * Prefix for slot names (e.g., "hour", "minute", "second")
  */
  @Prop() slotPrefix: string;

  private get _labelClasses() {
    return customTwMerge(baseLabelClasses, variantLabelClasses[this.variant]);
  }

  render() {
    const [digit1, digit2] = this.digits;

    return (
      <div class={wrapperClasses}>
        <div class={digitsClasses}>
          <slot name={`${this.slotPrefix}-digit-1`}>
            <wdpr-number-flipper>
              {digit1}
            </wdpr-number-flipper>
          </slot>
          <slot name={`${this.slotPrefix}-digit-2`}>
            <wdpr-number-flipper>
              {digit2}
            </wdpr-number-flipper>
          </slot>
        </div>
        <span class={this._labelClasses}>{this.label}</span>
      </div>
    );
  }
}

const wrapperClasses = 'flex flex-col items-center gap-050';
const digitsClasses = 'flex flex-row gap-050';
const baseLabelClasses = 'text-[12px] font-[800] leading-[16px] tracking-[1.2px] uppercase';

const variantLabelClasses: Record<CountdownVariant, string> = {
  primary: 'text-text-label',
  secondary: 'text-text-inverse',
};
